mapper.select:
SELECT DATE_FORMAT(l.lesson_date, '%Y-%m-%d') AS lesson_date,
       COUNT(*)                               AS cnt
FROM lesson l
JOIN member m ON l.client_id = m.id
WHERE YEAR(l.lesson_date)  = #{year}
  AND MONTH(l.lesson_date) = #{month}
  AND EXISTS (
      SELECT 1 FROM MEMBERSHIP_PT mpt
      WHERE mpt.member_id = m.id AND mpt.trainer_id = #{trainerId}
  )
GROUP BY l.lesson_date
